var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"REVELA_NPC_NULL_COMMAND","text":{"KOREA":"그러니까, 이번 주에 오기로 한 보급품이 운반 도중에 죄다 탈취되었다고?","JPN":"つまり、今週分の補給品が運ばれる途中に全部盗まれただと？","ENG":"Wait, you’re telling me the supplies set to arrive this week were all stolen?","TWN":"你的意思是，原本預計這週會抵達的補給品，在運送過程中遭洗劫一空？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"REVELA_NPC_NULL_SHIELD","text":{"KOREA":"후방에서 온 무전으로는 그렇답니다.","JPN":"後方からの連絡ではそうらしいです。","ENG":"That’s what the rear is reporting sir.","TWN":"後勤傳來的無線電是這麼說的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_SHIELD","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REVELA_NPC_NULL_SHIELD","text":{"KOREA":"방금 전에 아드님이 약탈당한 수송 차량을 찾으셨다던데, 밀알 한 톨 안 남아 있다더군요.","JPN":"先ほど息子さんが略奪された車両を見つけたそうですが、小麦の一粒も残されていなかったと。","ENG":"A moment ago, your son inspected a looted vehicle. He reported all of the supplies gone, sir.","TWN":"聽說剛才少爺找到遭搶的運輸車，結果裡面連一粒麥子都不剩。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_SHIELD","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REVELA_NPC_NULL_COMMAND","text":{"KOREA":"강경파랑 손잡은 놈이 빼돌린 거겠지. 개수작이 점점 진화하는군.","JPN":"強硬派と手を組んだやつが横取りしたんだろう。ふざけた真似がだんだんひどくなっているな。","ENG":"A soldier from the hardliners likely stole it. I see their dirty tactics are evolving.","TWN":"肯定是和強硬派合作的傢伙幹的！花招越來越多！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REVELA_NPC_NULL_SHIELD","text":{"KOREA":"어떡할까요? 보급 없이는 이번 주 배급도 유지하기 어렵습니다.","JPN":"どうしますか？　補給なしでは今週の配給も厳しくなります。","ENG":"What should we do, sir? Without supplies, it will be difficult to follow this week’s distribution schedule.","TWN":"現在怎麼辦？沒有補給品的話，這個禮拜的配給恐怕會有困難。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_SHIELD","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REVELA_NPC_NULL_COMMAND","text":{"KOREA":"끄응, 하여간 빌어먹을 강경파 놈들……. 역시 협정 건은…….","JPN":"ぐぬぬ、くそったれな強硬派め……やはり協定の件は……","ENG":"Huh, damn those bastards from the hardliners... As expected given the current agreement...","TWN":"嗯嗯，那些該死的強硬派……看來還是得跟他們談……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REVELC_NPC_NULL_NULL","text":{"KOREA":"말씀하시는 도중에 죄송합니다, 대장님.","JPN":"お話中、申し訳ありません、隊長。","ENG":"My apologies for interrupting, captain.","TWN":"隊長，抱歉打斷你們的談話。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELC_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REVELC_NPC_NULL_NULL","text":{"KOREA":"순찰조에서 보고했던 여자가 도착했습니다. 안으로 들일까요?","JPN":"見回り組が報告した女が来ました。中に入れましょうか？","ENG":"The woman the patrol team reported in has arrived, shall I let her in?","TWN":"巡邏隊說的那個女人到了，請她入內嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELC_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REVELA_NPC_NULL_COMMAND","text":{"KOREA":"오, 그래. 바로 들어오라고 해.","JPN":"お、いいぞ。早く入れろ。","ENG":"Oh, yes. Send her right in.","TWN":"嗯，好，讓她進來。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REVELA_NPC_NULL_COMMAND","text":{"KOREA":"보급은 내가 다른 병단들에게 잘 부탁하기로 하지. 대신 배급량도 순찰도 절반으로 줄여.","JPN":"補給は俺が他の兵団に頼むとする。代わりに配給量も見回りも半分にしろ。","ENG":"I’ll request more supplies from other troops, in the meantime, cut all rations by half.","TWN":"補給的事我再去拜託其他兵團，但配給量和巡邏的人數都要減半。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REVELA_NPC_NULL_SHIELD","text":{"KOREA":"잘 생각하셨습니다. 좋은 시간 되십시오.","JPN":"それがいいと思います。いいお時間を。","ENG":"Good idea, sir. Understood. Enjoy your evening.","TWN":"隊長英明，那就不耽誤隊長休息。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_SHIELD","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"일 때문에 많이 바쁘신 것 같네요, 자크 님. 여유가 생기실 때 다시 올까요?","JPN":"仕事でだいぶ忙しそうですね、ジャック様。暇な時を見計らって出直しましょうか？","ENG":"You seem so busy with your work, Sir Jacques. Shall I come back another time?","TWN":"札克隊長，你好像很忙的樣子，還是等你方便時我再過來？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"REVELA_NPC_NULL_COMMAND","text":{"KOREA":"아니야. 거기 앉지. 오느라 고생했어.","JPN":"いや、そこに座れ。よく来てくれた。","ENG":"Of course not. Please, take a seat. Thanks for coming all the way.","TWN":"不需要，你坐，辛苦你來這一趟。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REVELA_NPC_NULL_COMMAND","text":{"KOREA":"내 부하들이 건드리거나 하지는 않았나? 요즘 신병들은 기강이 해이해서 말이야.","JPN":"俺の部下たちが手を出したりしなかったか？　最近の新人は気が緩んでいるからな。","ENG":"Did you have any trouble with the men outside? Recruits these days lack discipline.","TWN":"我的手下應該沒有冒犯你吧？最近的新兵軍紀比較渙散一點。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"아뇨. 잠깐 길을 잃었는데 친절하게 안내까지 해 주더라고요.","JPN":"いいえ。少し道に迷ったところを親切に案内までしてくれましたよ。","ENG":"Oh, not at all, sir. I was lost for a bit, but your men gave such wonderful directions.","TWN":"沒有，我找不到路，他們還很親切地幫我指路呢～"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"REVELA_NPC_NULL_COMMAND","text":{"KOREA":"그래? 순찰조에게 포상이라도 줘야겠군.","JPN":"そうか？ 見回り組に褒美でもやらないとな。","ENG":"Is that so? I suppose I should give them a bonus.","TWN":"是嗎？看來我得打賞巡邏隊囉？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"REVELA_NPC_NULL_COMMAND","text":{"KOREA":"한동안은 내 침실에서 지내도록 해. 원하는 건 부하들에게 말하면 해결해 줄 거야.","JPN":"しばらくは俺の部屋で暮らせ。欲しいものは部下に言えば解決してくれるだろう。","ENG":"Please, stay in my bedroom for a while. If you need anything at all, tell my men and they will get it for you.","TWN":"你就先暫時住在我的寢室裡，有任何需要可以找我的手下，他們會替你處理。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"굉장히 신사적이시네요. 보는 눈도 없으니까 원하시는 대로 하셔도 될 텐데.","JPN":"とても紳士的ですね。監視の目もないし、思うままにしてもいいのに。","ENG":"Oh, you’re such a gentleman! I was expecting to do it as you please since there’s no one looking.","TWN":"你真是紳士呢～現在明明又沒有人在看，你想做什麼都可以。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"REVELA_NPC_NULL_COMMAND","text":{"KOREA":"흐흐. 그런 짐승 같은 짓은 못 배워 먹은 강경파 놈들이나 하는 거지.","JPN":"ふふ。そんな獣みたいな真似は出来損ない強硬派どもがやることさ。","ENG":"Ha. I’m not a savage like some of those bastards in the hardliners.","TWN":"呵呵，這種禽獸不如的事，強硬派的傢伙才幹得出來。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"REVELA_NPC_NULL_COMMAND","text":{"KOREA":"애초에 자네를 부른 것도 루이제 슈나이더와 닮아서이기도 하고.","JPN":"だいたい、君を呼んだのもルイーゼ・シュナイダーに似てるからだしな。","ENG":"You know, I requested you specifically because you remind me of Louise Schneider.","TWN":"我會找你來，只是因為你長得很像露易絲·修奈德。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……슈나이더?","JPN":"……シュナイダー？","ENG":"...Did you say Schneider?","TWN":"……修奈德？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"REVELA_NPC_NULL_COMMAND","text":{"KOREA":"오, 아는 눈치군. 요즘 젊은 사람들은 잘 모르는데.","JPN":"お、知ってるのか？　最近の若者は知らないことが多いんだが。","ENG":"Ah, so you know of her. Most kids these days have never heard of her.","TWN":"喔！看你的反應似乎是知道她，最近的年輕人都都不太認識她呢。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"REVELA_NPC_NULL_COMMAND","text":{"KOREA":"나는 루이제의 팬이었어.","JPN":"俺はルイーゼのファンだった。","ENG":"I was a huge fan of hers.","TWN":"我是露易絲的粉絲。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"REVELA_NPC_NULL_COMMAND","text":{"KOREA":"반정부주의 운동을 하던 시절에도 그 사람이 연주하는 날에는 반드시 건국기념전당에 찾아갔지.","JPN":"反政府主義の運動をやっていた頃も、あの人が演奏する日には必ず建国記念館を訪れた。","ENG":"Even during the early days of the anti-government movement, I would always visit the National Foundation Hall whenever she played.","TWN":"就連我進行反政府運動時，只要是她演奏的日子，我就會跑到建國紀念堂去看她表演。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"REVELA_NPC_NULL_COMMAND","text":{"KOREA":"최고의 연주자이자 작곡가였거든. 정부군이 나라를 이 지경으로만 안 만들었어도…….","JPN":"最高の演奏者で作曲家だったからな。政府軍が国をこんな様にしなかったら……","ENG":"She was the best performer and composer I’d ever seen. If only the government forces hadn’t brought the country to this point—","TWN":"她是當代最傑出的作曲家和演奏家，要不是政府軍把國家搞成這樣……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"REVELA_NPC_NULL_COMMAND","text":{"KOREA":"컥?!","JPN":"ぐはっ！？","ENG":"Ack?!","TWN":"唔？！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_05"},{"id":"L34_1","type":"dialog","speaker":"REVELA_NPC_NULL_COMMAND","text":{"KOREA":"이 빌어먹을 년이! 내가 누군지 알고 주먹을……!","JPN":"このくそ女が！　俺を誰だと思って拳を……！","ENG":"You bastard! Even knowing who I am, you...!","TWN":"你這臭女人！竟敢打我，你知道我是誰……！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"미안. 반군 나부랭이가 그 이름을 들먹이는 게 짜증나서.","JPN":"ごめん。反乱軍のやつがその名を言うのがむかついてね。","ENG":"Whoops, so sorry. It’s just so irritating to hear a scum like you talk about her.","TWN":"抱歉， 聽到叛軍雜碎提起這個名字，我就會渾身不舒服。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L37_1","type":"dialog","speaker":"REVELA_NPC_NULL_COMMAND","text":{"KOREA":"큭……! 이 년이, 어떻게 무기를……!","JPN":"くっ……！　この野郎、どうやって武器を……！","ENG":"Hrgh...! You... How were you able to bring a weapon...!","TWN":"可惡……！你怎麼會有槍……！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"네가 불렀다니까 몸수색도 안 하던데. 하긴 불러들인 말동무가 한둘이었어야지.","JPN":"君が呼んだと言ったら、身体検査もしなかったよ。まあ、私みたいのが一人や二人じゃなかったからね。","ENG":"Knowing it’s you who called me in, your men didn’t even conduct a simple body search. Guess you really did call in lots of company.","TWN":"我說是我是你找來的，就沒人對我搜身，應該是之前就有其他人來陪聊吧？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"REVELA_NPC_NULL_COMMAND","text":{"KOREA":"……어디서 보낸 거냐?","JPN":"……どこから来た？","ENG":"...Who sent you?","TWN":"……是誰派你來的？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"REVELA_NPC_NULL_COMMAND","text":{"KOREA":"강경파 놈들? 아니면 보안국?","JPN":"強硬派？　それとも保安局か？","ENG":"The hardliners? Or the National Security?","TWN":"強硬派？還是安全局？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그런 의문은 나랑 같이 도로를 달리면서 차분하게 생각해도 돼.","JPN":"それは私と一緒に道路を走りながらじっくり考えるといい。","ENG":"I’ll let you think about that while we’re on the road.","TWN":"這個問題，等我們上路後你再慢慢想吧。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"대학생 때부터 반군 나부랭이로 살면서 원수진 곳도 많을 거 아냐?","JPN":"大学の時から反乱軍をやりながら、作った敵も多いんじゃない？","ENG":"After all, you’ve been a part of the rebel forces ever since you were in college. You have a lot of enemies.","TWN":"你從大學就成為叛軍雜碎，到現在應該得罪過不少人吧？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"여기는 레버넌트. 타깃을 확보했습니다.","JPN":"こちらレヴナント。ターゲットを確保しました。","ENG":"This is Revenant. The target is in custody.","TWN":"這裡是亡靈，已經確認目標。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L49_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"좋다. 예정된 경로로 빠져나오도록. 맞은편 건물에 침투한 지원팀이 엄호를…… ","JPN":"わかった。予定のルートで脱出するように。向こうの建物に侵入した応援班が援護を…… ","ENG":"Good work. The support team has infiltrated the building across the street... ","TWN":"很好，接下來就照預定的路線離開，等埋伏在對面大樓的支援組發出暗號…… "},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L50_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"음?","JPN":"うむ？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>음?</color> 이라뇨. 불안하게 왜 그래요.","JPN":"<color=#ffd34c>うむ？</color>って。不安にさせないでください。","ENG":"Did you say <color=#ffd34c>Huh</color>? Don't make me worry.","TWN":"<color=#ffd34c>嗯？</color>什麼？你別嚇我！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"지원팀에서 응답이 없어. 교신 상태는 계속 양호했는데…….","JPN":"応援班からの応答がない。交信状態は良好だったはず……","ENG":"Support team is not responding. The comms were working fine...","TWN":"支援組沒回應，剛剛訊號都沒問題的……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……이런.","JPN":"……ちくしょう。","ENG":"Oh no...","TWN":"……可惡。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"REVELA_NPC_NULL_COMMAND","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"레버넌트, 응답하라! 방금 총성은 뭔가?","JPN":"レヴナント、応答せよ！　今の銃声はなんだ？","ENG":"Revenant, Come in! What was that noise?","TWN":"亡靈，回答我！剛剛的槍聲是怎麼回事？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"저격이에요. 탄흔 각도로 보아 지원팀이 침투해 있던 건물에서 날아왔습니다.","JPN":"狙撃です。弾痕の角度から見ると応援班が侵入した建物から飛んできました。","ENG":"Sniper! Judging from the trajectory of the bullet, it came from the building the support team infiltrated.","TWN":"有狙擊！看彈痕的角度，應該是從支援組埋伏的大樓開槍的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"저격? 설마 반군들이 냄새를 맡은 건가?","JPN":"狙撃？　まさか反乱軍が嗅ぎ付けてきたのか？","ENG":"A sniper? There’s no way the rebels could have caught on this fast.","TWN":"狙擊？難道是叛軍有發現異樣？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"아니, 그렇다고 해도……!","JPN":"いや、だとしても……！","ENG":"Wait, but still...!","TWN":"不對，就算是這樣……！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"제 걱정도 해 주시죠. 창문과 한 발짝만 더 가까웠어도 숨을 틈 없이 죽었을 텐데요.","JPN":"私の心配もしてください。あと一歩だけ窓に近づいたら死ぬところでしたよ。","ENG":"Hey, could you worry a little about me please? I’d be dead if I were just one step closer to the window.","TWN":"你也替我擔心一下吧！我只要再靠近窗戶一步，就命喪黃泉了好嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"돌발 상황을 우려하지 않았다면 자네를 귀국시키지도 않았어. 상황은?","JPN":"イレギュラーな状況を想定しなかったら、君を帰国させもしなかった。状況は？","ENG":"If I wasn’t concerned, I wouldn’t have ordered you back to the country immediately. What’s the situation?","TWN":"要不是擔心會有突發狀況，我也不會把你找回來。現在狀況如何？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"저 대신 타깃이 후두부에 총상을 입었습니다. 즉사예요.","JPN":"私の代わりにターゲットの後頭部に当たりました。即死です。","ENG":"I’m not the one who’s hurt. The target has been hit in the back of the head. Dead instantly.","TWN":"目標成為我的替死鬼，後腦杓中彈，立刻死亡。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"이런 빌어먹을……!","JPN":"このくそったれが……！","ENG":"Damn it...!","TWN":"該死的……！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_BIG"},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"더 빌어먹을 소식이 있는데 들어 보실래요?","JPN":"もっとくそったれなお知らせがありますが、聞きますか？","ENG":"I have more bad news. Would you like to hear it?","TWN":"還有更糟糕的消息，你想聽嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"REVELA_NPC_NULL_SHIELD","text":{"KOREA":"대장님! 경비대가 저격이 날아왔다고 합니다! 무사하십니까!","JPN":"隊長！　警備隊から狙撃があったという報告がありました！　無事ですか！","ENG":"Captain! The guards reported hearing gunfire! Are you alright sir?","TWN":"隊長！守衛隊發現有狙擊！隊長沒事吧？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REVELA_NPC_NULL_SHIELD","text":{"KOREA":"대답하십시오, 대장님! 대답이 없으시면 바로 문을 부수겠습니다!","JPN":"返事してください、隊長！　返事がなければドアを壊します！","ENG":"Please respond, sir! If you don’t answer, I will break down the door!","TWN":"隊長有聽到嗎？隊長！隊長再不說話的話，我們會立刻破門而入！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"우리 들어갈 묫자리나 찾아 두세요. 조용히 처리하긴 글렀어요.","JPN":"私たちの墓場でも探しておいてください。静かに解決するのは無理です。","ENG":"Locate a resting place for us. I won’t be able to handle this quietly.","TWN":"先替我們找好墓地吧，看來是無法難低調處理。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"}]`);export{e as default};